use sqisign_rs::nistapi::crypto_sign_open;
fn main() {
    let pk = hex::decode("07CCD21425136F6E865E497D2D4D208F0054AD81372066E817480787AAF7B2029550C89E892D618CE3230F23510BFBE68FCCDDAEA51DB1436B462ADFAF008A010B").unwrap();
    let sm = hex::decode("").unwrap();
    for _ in 0..200 {
        assert!(crypto_sign_open(&sm, &pk).is_ok());
    }
}
